// Press-to-paint benchmark.
//
// Seeds a fake "synced" job (red + blue 1080p test clips + tone audio,
// generated by ffmpeg into test-fixtures/), opens the editor in real
// Chromium with ?perf=1, starts playback, fires a beat-tap pattern of
// 1-2 hotkeys, then a couple of F holds. Reads the PerfHUD's bucket
// state from window.__perfBuckets and prints p50/p95/max per metric.
//
// Run:  node scripts/bench-press-to-paint.mjs
// (Requires the dev server on localhost:5174 + test-fixtures/ in place.)

import { chromium } from "playwright";
import { readFile, stat, mkdir } from "node:fs/promises";
import { spawnSync } from "node:child_process";
import path from "node:path";

const URL = process.env.URL ?? "http://localhost:5174/?perf=1";
const FIXTURES_DIR = path.join(process.cwd(), "test-fixtures");

// ---- Auto-generate fixtures via ffmpeg if missing ----
//
// 15s of motion content per cam (mandelbrot + life) at 1080p H.264 8 Mb/s
// — heavy enough to give the decoder real work, simple enough that ffmpeg
// can produce them in seconds. 15s tone audio for a master clock.
async function ensureFixture(name, ffmpegArgs) {
  const target = path.join(FIXTURES_DIR, name);
  try {
    await stat(target);
    return;
  } catch {
    // fall through and generate
  }
  await mkdir(FIXTURES_DIR, { recursive: true });
  console.error(`[bench] generating ${name}…`);
  const r = spawnSync("ffmpeg", ["-y", ...ffmpegArgs, target], {
    stdio: ["ignore", "ignore", "ignore"],
  });
  if (r.status !== 0) {
    throw new Error(
      `ffmpeg failed for ${name} (exit ${r.status}). Is ffmpeg on PATH?`,
    );
  }
}
await ensureFixture("cam-red.mp4", [
  "-f", "lavfi", "-i", "mandelbrot=size=1920x1080:rate=30,format=yuv420p",
  "-t", "15", "-c:v", "libx264", "-preset", "medium", "-b:v", "8M",
  "-pix_fmt", "yuv420p",
]);
await ensureFixture("cam-blue.mp4", [
  "-f", "lavfi", "-i", "life=size=1920x1080:rate=30:mold=10:r=30,format=yuv420p",
  "-t", "15", "-c:v", "libx264", "-preset", "medium", "-b:v", "8M",
  "-pix_fmt", "yuv420p",
]);
await ensureFixture("master.wav", [
  "-f", "lavfi", "-i", "sine=f=220:d=15",
  "-ac", "2", "-ar", "48000", "-c:a", "pcm_s16le",
]);

// ---- Load fixture media ----
const [redBuf, blueBuf, audioBuf] = await Promise.all([
  readFile(path.join(FIXTURES_DIR, "cam-red.mp4")),
  readFile(path.join(FIXTURES_DIR, "cam-blue.mp4")),
  readFile(path.join(FIXTURES_DIR, "master.wav")),
]);
const redB64 = redBuf.toString("base64");
const blueB64 = blueBuf.toString("base64");
const audioB64 = audioBuf.toString("base64");

// ---- Boot Chromium ----
const browser = await chromium.launch({
  headless: process.env.HEADLESS !== "0",
  // Force the real GPU compositor + Vulkan/Metal backend even in
  // headless mode so the bench actually exercises display:none vs
  // visibility GPU-layer differences. SwiftShader masks them.
  args: process.env.HEADLESS === "0"
    ? []
    : [
        "--use-gl=angle",
        "--enable-gpu-rasterization",
        "--enable-zero-copy",
        "--ignore-gpu-blocklist",
        "--enable-features=Vulkan,VaapiVideoDecoder",
      ],
});
const ctx = await browser.newContext({
  viewport: { width: 1440, height: 900 },
});
const page = await ctx.newPage();

const consoleErrors = [];
const pageErrors = [];
page.on("console", (m) => {
  if (m.type() === "error") consoleErrors.push(m.text());
});
page.on("pageerror", (e) => pageErrors.push(e.message));

await page.goto(URL, { waitUntil: "domcontentloaded" });

const isolated = await page.evaluate(() => crossOriginIsolated && typeof SharedArrayBuffer !== "undefined");
if (!isolated) {
  console.error("FAIL: cross-origin isolation not active");
  process.exit(2);
}

// ---- Seed the job into OPFS + IndexedDB ----
const jobId = "perfbench" + Math.random().toString(36).slice(2, 8);
await page.evaluate(
  async ({ jobId, redB64, blueB64, audioB64 }) => {
    function b64ToBlob(b64, mime) {
      const bin = atob(b64);
      const arr = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
      return new Blob([arr], { type: mime });
    }

    // Walk OPFS, creating directories as needed.
    async function dir(parent, name) {
      return await parent.getDirectoryHandle(name, { create: true });
    }
    async function writeFile(parent, name, blob) {
      const fh = await parent.getFileHandle(name, { create: true });
      const w = await fh.createWritable();
      await w.write(blob);
      await w.close();
    }

    const root = await navigator.storage.getDirectory();
    const jobsDir = await dir(root, "jobs");
    const jobDir = await dir(jobsDir, jobId);
    await writeFile(jobDir, "cam-1.mp4", b64ToBlob(redB64, "video/mp4"));
    await writeFile(jobDir, "cam-2.mp4", b64ToBlob(blueB64, "video/mp4"));
    await writeFile(jobDir, "audio.wav", b64ToBlob(audioB64, "audio/wav"));

    // Open the same IDB the app uses. Forcing the schema version to
    // match `DB_VERSION` (3) so `idb.openDB` doesn't trigger a fresh
    // upgrade if we run before the app has touched the DB.
    const dbReq = indexedDB.open("videoaudiosync", 3);
    const db = await new Promise((resolve, reject) => {
      dbReq.onupgradeneeded = () => {
        const d = dbReq.result;
        if (!d.objectStoreNames.contains("jobs")) {
          const s = d.createObjectStore("jobs", { keyPath: "id" });
          s.createIndex("by-createdAt", "createdAt");
        }
        if (!d.objectStoreNames.contains("audio-analysis")) {
          d.createObjectStore("audio-analysis", { keyPath: "jobId" });
        }
      };
      dbReq.onsuccess = () => resolve(dbReq.result);
      dbReq.onerror = () => reject(dbReq.error);
    });

    const job = {
      id: jobId,
      title: "perf-bench",
      videoFilename: "cam-red.mp4",
      audioFilename: "audio.wav",
      status: "synced",
      progress: { pct: 100, stage: "synced" },
      hasOutput: false,
      createdAt: Date.now(),
      schemaVersion: 2,
      durationS: 15,
      width: 1920,
      height: 1080,
      fps: 30,
      videos: [
        {
          kind: "video",
          id: "cam-1",
          filename: "cam-red.mp4",
          opfsPath: `jobs/${jobId}/cam-1.mp4`,
          color: "#FF5722",
          durationS: 15,
          width: 1920,
          height: 1080,
          fps: 30,
          sync: { offsetMs: 0, driftRatio: 1, confidence: 1 },
        },
        {
          kind: "video",
          id: "cam-2",
          filename: "cam-blue.mp4",
          opfsPath: `jobs/${jobId}/cam-2.mp4`,
          color: "#1F4E8C",
          durationS: 15,
          width: 1920,
          height: 1080,
          fps: 30,
          sync: { offsetMs: 0, driftRatio: 1, confidence: 1 },
        },
      ],
      cuts: [],
      sync: { offsetMs: 0, driftRatio: 1, confidence: 1 },
    };

    await new Promise((resolve, reject) => {
      const tx = db.transaction("jobs", "readwrite");
      tx.objectStore("jobs").put(job);
      tx.oncomplete = () => resolve(undefined);
      tx.onerror = () => reject(tx.error);
    });
    db.close();
  },
  { jobId, redB64, blueB64, audioB64 },
);

// ---- Navigate to the editor for the seeded job ----
await page.goto(`http://localhost:5174/job/${jobId}/edit?perf=1`, {
  waitUntil: "domcontentloaded",
});

// Wait for the editor to leave the "Loading editor…" state. The
// videoArea (MultiCamPreview) renders once both job + assets are set.
await page.waitForFunction(
  () => !document.body?.innerText?.includes("Loading editor"),
  null,
  { timeout: 15000 },
);

// Give the audio-analysis pre-step a moment, then a beat for the
// CamCanvas warmup play()→pause() cycle to settle.
await page.waitForTimeout(1500);

// ---- Start playback and fire a beat-tap pattern ----
// SPACE toggles play/pause. Then 1-2-1-2-1-2 with ~150 ms gaps simulates
// tapping eighth notes at ~200 BPM. F is a hold (down → wait → up).
await page.keyboard.press("Space");
await page.waitForTimeout(400);

const TAPS = ["1", "2", "1", "2", "1", "2", "1", "2", "1", "2"];
for (const k of TAPS) {
  await page.keyboard.press(k);
  await page.waitForTimeout(180);
}

// Two F holds.
for (let i = 0; i < 2; i++) {
  await page.keyboard.down("f");
  await page.waitForTimeout(220);
  await page.keyboard.up("f");
  await page.waitForTimeout(180);
}

// Stop playback.
await page.keyboard.press("Space");

// Wait for outstanding double-RAF perf measurements to flush.
await page.waitForTimeout(500);

// ---- Read the PerfHUD buckets ----
const result = await page.evaluate(() => {
  const buckets = window.__perfBuckets;
  if (!buckets) return null;
  function pct(s, p) {
    if (s.length === 0) return 0;
    const sorted = [...s].sort((a, b) => a - b);
    return sorted[Math.min(sorted.length - 1, Math.floor((sorted.length - 1) * p))];
  }
  const out = {};
  for (const [kind, b] of buckets.entries()) {
    out[kind] = {
      n: b.samples.length,
      samples: b.samples.map((v) => +v.toFixed(2)),
      p50: +pct(b.samples, 0.5).toFixed(2),
      p95: +pct(b.samples, 0.95).toFixed(2),
      max: b.samples.length ? +Math.max(...b.samples).toFixed(2) : 0,
    };
  }
  return out;
});

if (process.env.JSON === "1") {
  console.log(JSON.stringify({ jobId, result }));
} else {
  console.log(JSON.stringify({
    jobId,
    result,
    consoleErrors,
    pageErrors,
  }, null, 2));
}

await browser.close();
